public class TitleCaseConverter {
    // List of exception words that should not be capitalized unless they are the first word
    private static final List<String> EXCEPTION_WORDS = List.of("of", "the", "is", "and");

    public static String convertToTitleCase(String input) {
        if (input == null || input.isEmpty()) {
            return "";
        }

        // Capitalize the first letter
        char firstChar = input.charAt(0);
        if (firstChar >= 'a' && firstChar <= 'z') {
            input = Character.toUpperCase(firstChar) + input.substring(1);
        }

        // Process each word
        StringBuilder result = new StringBuilder();
        String[] words = input.split("\\s+");

        for (int i = 0; i < words.length; i++) {
            String word = words[i];

            // Check if the word is an exception word and not the first word
            if (i > 0 && EXCEPTION_WORDS.contains(word)) {
                result.append(word);
            } else {
                // Capitalize the first letter of the word if it's not an exception word
                if (word.length() > 0 && word.charAt(0) >= 'a' && word.charAt(0) <= 'z') {
                    result.append(Character.toUpperCase(word.charAt(0)));
                }
                result.append(word.substring(1));
            }
        }

        return result.toString();
    }

    // Test the method
    public static void main(String[] args) {
